CREATE OR REPLACE FUNCTION OFSERM.ABL_CAP_MITIGANT_DATA_POPULATION(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_CAP_MITIGANTS(N_COUNTRY_SKEY,N_MIS_DATE_SKEY,N_GAAP_SKEY,N_INSTRUMENT_SKEY,N_ISSUE_SKEY,N_MARGIN_TYPE_SKEY,N_MITIGANT_SKEY,N_MITIGANT_TYPE_SKEY,N_NETTING_AGREEMENT_SKEY,F_FINANCIAL_ENTITY_IND,F_REGULATED_FIN_ENTITY_IND,N_ISSUER_SKEY,F_ELIGIBILITY_FLAG,F_QUALIFIED_CCP_FLAG,N_CENTRAL_COUNTERPARTY_SKEY,N_CLEARING_MEMBER_SKEY,N_GROUP_ASSET_SIZE,N_ISSUER_ANNUAL_SALES,N_MATERIALITY_THRSHLD_LOSS_AMT,N_MITIGANT_VALUE,N_ORIGINAL_MATURITY,N_RESIDUAL_MATURITY,N_RUN_PARAMETER_SETUP_SKEY,N_RUN_SKEY,N_STANDARD_ISSUER_TYPE_SKEY,V_APPROACH_TYPE,N_CAP_APPROACH_TYPE_SKEY,N_CAP_RECORD_TYPE_SKEY,V_RECORD_TYPE,N_RUN_IDENTIFIER_SKEY,N_STD_MITIGANT_TYPE_SKEY,N_FAIR_VALUE_RCY,N_ISSUER_TYPE_SKEY,N_BASEL_ISSUER_TYPE_SKEY,D_MATURITY_DATE,D_MITIGANT_START_DATE,F_CLEARED_TRANSACTION_FLAG,F_COLL_SEGREGATED_FLAG,F_CONSENT_TO_ADJUST_MATURITY,F_DIL_RISK_MITIGANT_FLAG,F_ELIG_MUTUAL_FUND_IND,F_ELIG_NON_MAIN_INDEX_IND,F_EQUITY_TRADED_FLAG,F_EXCHANGE_TRADED_FLAG,F_GUARANTEE_REVOKABLE_FLAG,F_INVESTMENT_GRADE_FLAG,F_MAIN_INDEX_IND,F_RE_SECURITIZED_FLAG,F_SECURITIZED_FLAG,F_SENIOR_COLL_FLAG,F_UNRATED_DEB_SEC_ELG_FLAG,N_COLL_MKT_VALUE,N_DEFAULTED_POSITION,N_HOLDING_PERIOD,N_LGD_PERCENT,N_ORIGINAL_MITIGANT_VALUE,N_PD_PERCENT,N_POST_VOL_HC_COLL_VALUE,N_REMARGIN_FREQUENCY,N_REVAL_FREQUENCY,V_CCY_CODE,V_MARGIN_TYPE)SELECT  /*+PARALLEL (4)*/ to_char(DIM_COUNTRY.N_COUNTRY_SKEY),to_char(DIM_DATES.N_DATE_SKEY),to_char(DIM_GAAP.N_GAAP_SKEY),to_char(DIM_INSTRUMENT_CONTRACT.N_INSTRUMENT_SKEY),to_char(DIM_ISSUE.N_ISSUE_SKEY),to_char(DIM_MARGIN_TYPE.N_MARGIN_TYPE_SKEY),to_char(DIM_MITIGANT.N_MITIGANT_SKEY),to_char(DIM_MITIGANT_TYPE.N_MITIGANT_TYPE_SKEY),to_char(DIM_NETTING_AGREEMENT.N_NETTING_AGREEMENT_SKEY),DIM_PARTY.F_FINANCIAL_ENTITY_IND,DIM_PARTY.F_REGULATED_FIN_ENTITY_IND,to_char(DIM_PARTY.N_PARTY_SKEY),'Y',DIM_PARTY_CCP.f_qualified_ccp_flag,DIM_PARTY_CCP.n_party_skey,DIM_PARTY_CM.n_party_skey,FSI_CAP_PARTY_FINANCIALS.N_GROUP_ASSET_SIZE * A_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,FSI_CAP_PARTY_FINANCIALS.N_SALES_AMT * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_MITIGANTS.N_MATERIALITY_THRSHLD_LOSS_AMT * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_MITIGANTS.N_MITIGANT_VALUE * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,(STG_MITIGANTS.D_MATURITY_DATE -STG_MITIGANTS.D_VALUE_DATE)/365,(STG_MITIGANTS.D_MATURITY_DATE -STG_MITIGANTS.FIC_MIS_DATE )/365,RUN_PARAMETERS.N_RUN_PARAMETER_SETUP_SKEY,'870',FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY,FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE,to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE,to_char(FSI_CAP_REC_TYPE_APPR_TYPE_MAP.N_REC_TYPE_APPR_TYPE_MAP_SKEY),to_char(FSI_MITIGANT_TYPE_RECLASS.N_STD_MITIGANT_TYPE_SKEY),to_char(FSI_MITIGANT_VALUATION_DETAILS.N_FAIR_VALUE),to_char(FSI_PARTY_TYPE_CLASSIFICATION.N_PARTY_TYPE_SKEY),to_char(FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY),STG_MITIGANTS.D_MATURITY_DATE,STG_MITIGANTS.D_MITIGANT_START_DATE,STG_MITIGANTS.F_CLEARED_TRANSACTION_FLAG,STG_MITIGANTS.F_COLL_SEGREGATED_FLAG,STG_MITIGANTS.F_CONSENT_TO_ADJUST_MATURITY,STG_MITIGANTS.F_DIL_RISK_MITIGANT_FLAG,STG_MITIGANTS.F_ELIG_MUTUAL_FUND_IND,STG_MITIGANTS.F_ELIG_NON_MAIN_INDEX_IND,STG_MITIGANTS.F_EQUITY_TRADED_FLAG,STG_MITIGANTS.F_EXCHANGE_TRADED_FLAG,STG_MITIGANTS.F_GUARANTEE_REVOKABLE_FLAG,STG_MITIGANTS.F_INVESTMENT_GRADE_FLAG,STG_MITIGANTS.F_MAIN_INDEX_IND,STG_MITIGANTS.F_RE_SECURITIZED_FLAG,STG_MITIGANTS.F_SECURITIZED_FLAG,STG_MITIGANTS.F_SENIOR_COLL_FLAG,STG_MITIGANTS.F_UNRATED_DEBT_SEC_ELIG_FLAG,to_char(STG_MITIGANTS.N_COLL_MKT_VALUE),to_char(STG_MITIGANTS.N_DEFAULTED_POSITION),to_char(STG_MITIGANTS.N_HOLDING_PERIOD),to_char(STG_MITIGANTS.N_LGD_PERCENT),to_char(STG_MITIGANTS.N_ORIGINAL_MITIGANT_VALUE),to_char(STG_MITIGANTS.N_PD_PERCENT),to_char(STG_MITIGANTS.N_POST_VOL_HC_COLL_VALUE),to_char(STG_MITIGANTS.N_REMARGIN_FREQUENCY),to_char(STG_MITIGANTS.N_REVAL_FREQUENCY),STG_MITIGANTS.V_CCY_CODE,STG_MITIGANTS.V_MARGIN_TYPE FROM STG_MITIGANTS INNER JOIN DIM_DATES ON DIM_DATES.d_calendar_date = to_date('20260331','YYYYMMDD') AND STG_MITIGANTS.FIC_MIS_DATE = to_date('20260331','YYYYMMDD') AND COALESCE(STG_MITIGANTS.F_CVA_HEDGE, 'N') = 'N'  /*AND ((STG_MITIGANTS.D_MATURITY_DATE - STG_MITIGANTS.FIC_MIS_DATE) / 365) > 0 */ INNER JOIN DIM_RUN ON DIM_RUN.n_run_skey = '870' INNER JOIN DIM_MITIGANT ON STG_MITIGANTS.V_MITIGANT_CODE = DIM_MITIGANT.V_MITIGANT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_MITIGANT.D_RECORD_START_DATE AND DIM_MITIGANT.D_RECORD_END_DATE LEFT OUTER JOIN DIM_GAAP ON STG_MITIGANTS.V_GAAP_CODE = DIM_GAAP.V_GAAP_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_GAAP.D_RECORD_START_DATE AND DIM_GAAP.D_RECORD_END_DATE LEFT OUTER JOIN DIM_MITIGANT_TYPE ON STG_MITIGANTS.V_MITIGANT_TYPE_CODE = DIM_MITIGANT_TYPE.V_MITIGANT_TYPE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_MITIGANT_TYPE.D_RECORD_START_DATE AND DIM_MITIGANT_TYPE.D_RECORD_END_DATE LEFT OUTER JOIN DIM_COUNTRY ON COALESCE(STG_MITIGANTS.V_COUNTRY_CODE, 'MSG') = DIM_COUNTRY.V_COUNTRY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_COUNTRY.D_RECORD_START_DATE AND DIM_COUNTRY.D_RECORD_END_DATE LEFT OUTER JOIN DIM_PARTY ON STG_MITIGANTS.v_Issuer_Code = DIM_PARTY.v_party_id AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY.D_RECORD_START_DATE AND DIM_PARTY.D_RECORD_END_DATE LEFT OUTER JOIN DIM_PARTY DIM_PARTY_CCP ON COALESCE(STG_MITIGANTS.v_central_counterparty_code, 'MSG') = DIM_PARTY_CCP.v_party_id AND to_date('20260331','YYYYMMDD') BETWEEN COALESCE(DIM_PARTY_CCP.D_RECORD_START_DATE, to_date('20260331','YYYYMMDD')) AND COALESCE(DIM_PARTY_CCP.D_RECORD_END_DATE, to_date('20260331','YYYYMMDD')) LEFT OUTER JOIN DIM_PARTY DIM_PARTY_CM ON COALESCE(STG_MITIGANTS.v_clearing_member_code, 'MSG') = DIM_PARTY_CM.v_party_id AND to_date('20260331','YYYYMMDD') BETWEEN COALESCE(DIM_PARTY_CM.D_RECORD_START_DATE, to_date('20260331','YYYYMMDD')) AND COALESCE(DIM_PARTY_CM.D_RECORD_END_DATE, to_date('20260331','YYYYMMDD')) LEFT OUTER JOIN DIM_PARTY_TYPE ON COALESCE(DIM_PARTY.V_PARTY_TYPE, 'MSG') = DIM_PARTY_TYPE.V_PARTY_TYPE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY_TYPE.D_RECORD_START_DATE AND DIM_PARTY_TYPE.D_RECORD_END_DATE LEFT OUTER JOIN FSI_PARTY_TYPE_CLASSIFICATION ON DIM_PARTY_TYPE.n_party_type_skey = FSI_PARTY_TYPE_CLASSIFICATION.n_party_type_skey AND FSI_PARTY_TYPE_CLASSIFICATION.n_run_skey = '870' LEFT OUTER JOIN FSI_MITIGANT_TYPE_RECLASS ON DIM_MITIGANT_TYPE.N_MITIGANT_TYPE_SKEY = FSI_MITIGANT_TYPE_RECLASS.N_MITIGANT_TYPE_SKEY AND FSI_MITIGANT_TYPE_RECLASS.n_run_skey = '870' LEFT OUTER JOIN DIM_ISSUE ON STG_MITIGANTS.v_Instrument_Code = DIM_ISSUE.v_issue_code AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ISSUE.D_RECORD_START_DATE AND DIM_ISSUE.D_RECORD_END_DATE LEFT OUTER JOIN FSI_CAP_PARTY_FINANCIALS ON FSI_CAP_PARTY_FINANCIALS.N_PARTY_SKEY = DIM_PARTY.N_PARTY_SKEY AND FSI_CAP_PARTY_FINANCIALS.n_run_skey = '870' LEFT OUTER JOIN DIM_INSTRUMENT_CONTRACT ON DIM_INSTRUMENT_CONTRACT.V_INSTRUMENT_CODE = STG_MITIGANTS.V_INSTRUMENT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_INSTRUMENT_CONTRACT.D_RECORD_START_DATE AND DIM_INSTRUMENT_CONTRACT.D_RECORD_END_DATE LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION ON FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY = '870' AND FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = STG_MITIGANTS.V_CCY_CODE LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION A_FSI_CAP_CURRENCY_CONVERSION ON FSI_CAP_PARTY_FINANCIALS.N_RUN_SKEY = A_FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND A_FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = FSI_CAP_PARTY_FINANCIALS.V_CCY_CODE LEFT OUTER JOIN FSI_CAP_RUN_EXE_PARAMETERS ON FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY = '870' INNER JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'NONSEC' LEFT OUTER JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SKEY INNER JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE INNER JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'MITIGANT' LEFT OUTER JOIN DIM_MARGIN_TYPE ON DIM_MARGIN_TYPE.V_MARGIN_TYPE_CD = STG_MITIGANTS.V_MARGIN_TYPE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_MARGIN_TYPE.D_RECORD_START_DATE AND DIM_MARGIN_TYPE.D_RECORD_END_DATE LEFT OUTER JOIN DIM_NETTING_AGREEMENT ON DIM_NETTING_AGREEMENT.V_NETTING_AGREEMENT_CODE = STG_MITIGANTS.V_NETTING_AGREEMENT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_NETTING_AGREEMENT.D_RECORD_START_DATE AND DIM_NETTING_AGREEMENT.D_RECORD_END_DATE LEFT OUTER JOIN FSI_MITIGANT_VALUATION_DETAILS ON FSI_MITIGANT_VALUATION_DETAILS.V_MITIGANT_CODE = STG_MITIGANTS.V_MITIGANT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN FSI_MITIGANT_VALUATION_DETAILS.D_RECORD_START_DATE AND FSI_MITIGANT_VALUATION_DETAILS.D_RECORD_END_DATE LEFT JOIN FSI_CAP_REC_TYPE_APPR_TYPE_MAP ON FSI_CAP_REC_TYPE_APPR_TYPE_MAP.V_RECORD_TYPE = FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE AND FSI_CAP_REC_TYPE_APPR_TYPE_MAP.V_APPROACH_TYPE = FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE WHERE 1=1 AND STG_MITIGANTS.FIC_MIS_DATE = to_date('20260331','YYYYMMDD') AND COALESCE(STG_MITIGANTS.F_CVA_HEDGE, 'N') = 'N' /* AND ((STG_MITIGANTS.D_MATURITY_DATE -STG_MITIGANTS.FIC_MIS_DATE )/365)>0 */ LOG ERRORS INTO FSI_CAP_MITIGANTS$ ('1776768362454_10979798_20260331_1_Job_1582195884273') REJECT LIMIT 0;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
